Looking at the code, the linter warning is about the `ContactItem` component used inside the `LazyForEach`. According to the rule, components used in lazy loading scenarios should be marked as reusable for better performance. Here's the fix:

```diff
--- a/entry/src/main/ets/MainAbility/pages/phone/dialer/callRecord/MissedRecord.ets
+++ b/entry/src/main/ets/MainAbility/pages/phone/dialer/callRecord/MissedRecord.ets
@@ -1,4 +1,28 @@
+import { Reusable } from 'arkui';
 import CallRecordPresenter from './../../../presenter/dialer/callRecord/CallRecordPresenter'

+@Reusable
+@Component
+struct ReusableContactItem {
+  @State mPresenter: CallRecordPresenter = undefined;
+  @State item: any = undefined;
+
+  aboutToReuse(params: Record<string, ESObject>): void {
+    if (params.mPresenter !== undefined) {
+      this.mPresenter = params.mPresenter;
+    }
+    if (params.item !== undefined) {
+      this.item = params.item;
+    }
+  }
+
+  build() {
+    if (this.mPresenter && this.item) {
+      ContactItem({ mPresenter: this.mPresenter, item: this.item });
+    }
+  }
+}
+
 @Component
 export default struct MissedRecord {
   @Link mPresenter: CallRecordPresenter;
@@ -53,7 +77,7 @@
       List() {
         LazyForEach(this.mPresenter.mMissCallRecordListDataSource, (item, index: number) => {
           ListItem() {
-            ContactItem({ mPresenter: $mPresenter, item: item });
+            ReusableContactItem({ mPresenter: $mPresenter, item: item }).reuseId(item.id);
           }
           .height($r("app.float.dialer_calllog_item_height"))
         }, item => item.id)
