+@Reusable
+@Component
+struct MemberToolbar {
+  @Link presenter: SelectMemberSendMessagePresenter;
+  @Prop splitStatus: SplitStatus;
+  @Prop fontSizeScale: number;
+  @Prop isShowSmartWindow: boolean;
+
+  aboutToReuse(params: Record<string, Object>): void {
+    this.presenter = params.presenter as SelectMemberSendMessagePresenter;
+    this.splitStatus = params.splitStatus as SplitStatus;
+    this.fontSizeScale = params.fontSizeScale as number;
+    this.isShowSmartWindow = params.isShowSmartWindow as boolean;
+  }
+
+  build() {
+    Row() {
+      Column() {
+        SymbolGlyph($r('sys.symbol.checkmark'))
+          .fontSize($r('app.float.id_card_image_small'))
+          .fontColor([$r('app.color.skin_icon_primary')])
+          .margin({ bottom: $r('app.float.id_card_margin_sm') })
+          .opacity(this.presenter.selectedCount > 0 ? 1 : $r('sys.float.alpha_tertiary'))
+
+        Text($r('app.string.choose'))
+          .fontColor(this.presenter.selectedCount > 0 ? $r('app.color.skin_font_primary') : $r('app.color.skin_font_tertiary'))
+          .fontSize(DisplaySplitUtil.isHorizonSplit(this.splitStatus) ||
+          DisplaySplitUtil.isVerticalSplit(this.splitStatus) ? '10vp' : $r('sys.float.Caption_M'))
+          .fontWeight(FontWeight.Medium)
+      }
+      .enabled(this.presenter.selectedCount > 0 ? true : false)
+      .width('50%')
+      .height('100%')
+      .alignItems(HorizontalAlign.Center)
+      .justifyContent(FlexAlign.Center)
+      .onClick(() => {
+        this.presenter.sendMessage();
+      })
+
+      Column() {
+        SymbolGlyph(this.presenter.isSelectNumber ?
+          (this.presenter.isSelectAll ?
+          $r('sys.symbol.checkmark_square_on_square_fill') : $r('sys.symbol.checkmark_square_on_square'))
+        : $r('sys.symbol.checkmark_square_on_square_fill')
+          )
+          .fontSize($r('app.float.id_card_image_small'))
+          .fontColor(
+          [this.presenter.isSelectNumber ? (this.presenter.isSelectAll ? $r('app.color.skin_font_emphasize')
+            : $r('app.color.skin_icon_primary')) : $r('app.color.skin_font_tertiary')])
+
+        Text(this.presenter.isSelectNumber ?
+          (this.presenter.isSelectAll ? $r('app.string.unselect_all') : $r('app.string.select_all')) :
+        $r('app.string.unselect_all')
+          )
+          .fontColor(this.presenter.isSelectNumber ?
+            (this.presenter.isSelectAll ?
+            $r('app.color.skin_font_emphasize') : $r('app.color.skin_icon_primary')) :
+           $r('app.color.skin_font_tertiary')
+            )
+          .fontSize(DisplaySplitUtil.isHorizonSplit(this.splitStatus) ||
+          DisplaySplitUtil.isVerticalSplit(this.splitStatus) ? '10vp' : $r('sys.float.Caption_M'))
+          .fontWeight(FontWeight.Medium)
+          .margin({ top: $r('app.float.id_card_margin_sm') })
+      }
+      .width('50%')
+      .height('100%')
+      .alignItems(HorizontalAlign.Center)
+      .justifyContent(FlexAlign.Center)
+      .onClick(() => {
+        this.presenter.clickSelectAll();
+      })
+    }
+    .justifyContent(FlexAlign.Center)
+    .alignItems(VerticalAlign.Center)
+    .width('100%')
+    .height(this.fontSizeScale > 5 && this.isShowSmartWindow ? '60vp' : $r('app.float.id_toolbar_height'))
+    .padding({
+      left: $r('app.float.id_card_margin_max'),
+      right: $r('app.float.id_card_margin_max')
+    })
+  }
+}
